   186→/// Horner-encode up to 9 Zq values into a u128.
   187→/// Encoding: v0 + Q*(v1 + Q*(v2 + ... + Q*v8))
   188→fn pack_9(vals: Span<Zq>) -> u128 {
   189→    let n = vals.len();
   190→    match n {
   191→        0 => 0_u128,
   192→        1 => {
   193→            let a: Zq = v(vals, 0);
   194→            upcast(a)
   195→        },
   196→        2 => {
   197→            let a1: Acc1 = add(v(vals, 0), mul(Q_CONST, v(vals, 1)));
   198→            upcast(a1)
   199→        },
   200→        3 => {
   201→            let a1: Acc1 = add(v(vals, 1), mul(Q_CONST, v(vals, 2)));
   202→            let a2: Acc2 = add(v(vals, 0), mul(Q_CONST, a1));
   203→            upcast(a2)
   204→        },
   205→        4 => {
   206→            let a1: Acc1 = add(v(vals, 2), mul(Q_CONST, v(vals, 3)));
   207→            let a2: Acc2 = add(v(vals, 1), mul(Q_CONST, a1));
   208→            let a3: Acc3 = add(v(vals, 0), mul(Q_CONST, a2));
   209→            upcast(a3)
   210→        },
   211→        5 => {
   212→            let a1: Acc1 = add(v(vals, 3), mul(Q_CONST, v(vals, 4)));
   213→            let a2: Acc2 = add(v(vals, 2), mul(Q_CONST, a1));
   214→            let a3: Acc3 = add(v(vals, 1), mul(Q_CONST, a2));
   215→            let a4: Acc4 = add(v(vals, 0), mul(Q_CONST, a3));
   216→            upcast(a4)
   217→        },
   218→        6 => {
   219→            let a1: Acc1 = add(v(vals, 4), mul(Q_CONST, v(vals, 5)));
   220→            let a2: Acc2 = add(v(vals, 3), mul(Q_CONST, a1));
   221→            let a3: Acc3 = add(v(vals, 2), mul(Q_CONST, a2));
   222→            let a4: Acc4 = add(v(vals, 1), mul(Q_CONST, a3));
   223→            let a5: Acc5 = add(v(vals, 0), mul(Q_CONST, a4));
   224→            upcast(a5)
   225→        },
   226→        7 => {
   227→            let a1: Acc1 = add(v(vals, 5), mul(Q_CONST, v(vals, 6)));
   228→            let a2: Acc2 = add(v(vals, 4), mul(Q_CONST, a1));
   229→            let a3: Acc3 = add(v(vals, 3), mul(Q_CONST, a2));
   230→            let a4: Acc4 = add(v(vals, 2), mul(Q_CONST, a3));
   231→            let a5: Acc5 = add(v(vals, 1), mul(Q_CONST, a4));
   232→            let a6: Acc6 = add(v(vals, 0), mul(Q_CONST, a5));
   233→            upcast(a6)
   234→        },
   235→        8 => {
   236→            let a1: Acc1 = add(v(vals, 6), mul(Q_CONST, v(vals, 7)));
   237→            let a2: Acc2 = add(v(vals, 5), mul(Q_CONST, a1));
   238→            let a3: Acc3 = add(v(vals, 4), mul(Q_CONST, a2));
   239→            let a4: Acc4 = add(v(vals, 3), mul(Q_CONST, a3));
   240→            let a5: Acc5 = add(v(vals, 2), mul(Q_CONST, a4));
   241→            let a6: Acc6 = add(v(vals, 1), mul(Q_CONST, a5));
   242→            let a7: Acc7 = add(v(vals, 0), mul(Q_CONST, a6));
   243→            upcast(a7)
   244→        },
   245→        9 => {
   246→            let a1: Acc1 = add(v(vals, 7), mul(Q_CONST, v(vals, 8)));
   247→            let a2: Acc2 = add(v(vals, 6), mul(Q_CONST, a1));
   248→            let a3: Acc3 = add(v(vals, 5), mul(Q_CONST, a2));
   249→            let a4: Acc4 = add(v(vals, 4), mul(Q_CONST, a3));
   250→            let a5: Acc5 = add(v(vals, 3), mul(Q_CONST, a4));
   251→            let a6: Acc6 = add(v(vals, 2), mul(Q_CONST, a5));
   252→            let a7: Acc7 = add(v(vals, 1), mul(Q_CONST, a6));
   253→            let a8: Acc8 = add(v(vals, 0), mul(Q_CONST, a7));
   254→            upcast(a8)
   255→        },
   256→        _ => core::panic_with_felt252('pack_9: count > 9'),
   257→    }
   258→}
