   474→            *self.s8, *self.s9, *self.s10, *self.s11, *self.s12, *self.s13, *self.s14, *self.s15,
   475→            *self.s16, *self.s17, *self.s18, *self.s19, *self.s20, *self.s21, *self.s22, *self.s23,
   476→            *self.s24, *self.s25, *self.s26, *self.s27, *self.s28,
   477→        ]
   478→            .span()
   479→    }
   480→}
