    97→// Identity: (Q-1) + Q*(Q^(N+1)-1) = Q^(N+2) - 1
    98→// =============================================================================
    99→
   100→impl AddZqMulQAcc0Impl of AddHelper<Zq, MulQAcc0> {
   101→    type Result = Acc1;
   102→}
   103→
   104→impl AddZqMulQAcc1Impl of AddHelper<Zq, MulQAcc1> {
   105→    type Result = Acc2;
