   180→/// Helper: get a Zq value from a Zq span
   181→#[inline(always)]
   182→fn v(vals: Span<Zq>, i: usize) -> Zq {
   183→    *vals.at(i)
   184→}
   185→
   186→/// Horner-encode up to 9 Zq values into a u128.
   187→/// Encoding: v0 + Q*(v1 + Q*(v2 + ... + Q*v8))
   188→fn pack_9(vals: Span<Zq>) -> u128 {
   189→    let n = vals.len();
   190→    match n {
   191→        0 => 0_u128,
   192→        1 => {
   193→            let a: Zq = v(vals, 0);
   194→            upcast(a)
   195→        },
   196→        2 => {
   197→            let a1: Acc1 = add(v(vals, 0), mul(Q_CONST, v(vals, 1)));
   198→            upcast(a1)
   199→        },
   200→        3 => {
   201→            let a1: Acc1 = add(v(vals, 1), mul(Q_CONST, v(vals, 2)));
   202→            let a2: Acc2 = add(v(vals, 0), mul(Q_CONST, a1));
   203→            upcast(a2)
   204→        },
   205→        4 => {
   206→            let a1: Acc1 = add(v(vals, 2), mul(Q_CONST, v(vals, 3)));
   207→            let a2: Acc2 = add(v(vals, 1), mul(Q_CONST, a1));
   208→            let a3: Acc3 = add(v(vals, 0), mul(Q_CONST, a2));
   209→            upcast(a3)
   210→        },
   211→        5 => {
   212→            let a1: Acc1 = add(v(vals, 3), mul(Q_CONST, v(vals, 4)));
   213→            let a2: Acc2 = add(v(vals, 2), mul(Q_CONST, a1));
   214→            let a3: Acc3 = add(v(vals, 1), mul(Q_CONST, a2));
   215→            let a4: Acc4 = add(v(vals, 0), mul(Q_CONST, a3));
   216→            upcast(a4)
   217→        },
   218→        6 => {
   219→            let a1: Acc1 = add(v(vals, 4), mul(Q_CONST, v(vals, 5)));
   220→            let a2: Acc2 = add(v(vals, 3), mul(Q_CONST, a1));
   221→            let a3: Acc3 = add(v(vals, 2), mul(Q_CONST, a2));
   222→            let a4: Acc4 = add(v(vals, 1), mul(Q_CONST, a3));
   223→            let a5: Acc5 = add(v(vals, 0), mul(Q_CONST, a4));
   224→            upcast(a5)
   225→        },
   226→        7 => {
   227→            let a1: Acc1 = add(v(vals, 5), mul(Q_CONST, v(vals, 6)));
   228→            let a2: Acc2 = add(v(vals, 4), mul(Q_CONST, a1));
   229→            let a3: Acc3 = add(v(vals, 3), mul(Q_CONST, a2));
   230→            let a4: Acc4 = add(v(vals, 2), mul(Q_CONST, a3));
   231→            let a5: Acc5 = add(v(vals, 1), mul(Q_CONST, a4));
   232→            let a6: Acc6 = add(v(vals, 0), mul(Q_CONST, a5));
   233→            upcast(a6)
   234→        },
   235→        8 => {
   236→            let a1: Acc1 = add(v(vals, 6), mul(Q_CONST, v(vals, 7)));
   237→            let a2: Acc2 = add(v(vals, 5), mul(Q_CONST, a1));
   238→            let a3: Acc3 = add(v(vals, 4), mul(Q_CONST, a2));
   239→            let a4: Acc4 = add(v(vals, 3), mul(Q_CONST, a3));
   240→            let a5: Acc5 = add(v(vals, 2), mul(Q_CONST, a4));
   241→            let a6: Acc6 = add(v(vals, 1), mul(Q_CONST, a5));
   242→            let a7: Acc7 = add(v(vals, 0), mul(Q_CONST, a6));
   243→            upcast(a7)
   244→        },
   245→        9 => {
   246→            let a1: Acc1 = add(v(vals, 7), mul(Q_CONST, v(vals, 8)));
   247→            let a2: Acc2 = add(v(vals, 6), mul(Q_CONST, a1));
   248→            let a3: Acc3 = add(v(vals, 5), mul(Q_CONST, a2));
   249→            let a4: Acc4 = add(v(vals, 4), mul(Q_CONST, a3));
   250→            let a5: Acc5 = add(v(vals, 3), mul(Q_CONST, a4));
   251→            let a6: Acc6 = add(v(vals, 2), mul(Q_CONST, a5));
   252→            let a7: Acc7 = add(v(vals, 1), mul(Q_CONST, a6));
   253→            let a8: Acc8 = add(v(vals, 0), mul(Q_CONST, a7));
   254→            upcast(a8)
   255→        },
   256→        _ => core::panic_with_felt252('pack_9: count > 9'),
   257→    }
   258→}
   259→
   260→/// Unpack a u128 into `count` Zq values using iterated DivRem by Q.
   261→fn unpack_9(packed: u128, count: usize, ref output: Array<Zq>) {
   262→    if count == 0 {
   263→        return;
   264→    }
   265→    let acc8: Acc8 = downcast(packed).expect('invalid packed value');
   266→    let (acc7, r0) = bounded_int_div_rem(acc8, NZ_Q);
   267→    output.append(r0);
   268→    if count == 1 {
   269→        return;
   270→    }
   271→    let (acc6, r1) = bounded_int_div_rem(acc7, NZ_Q);
   272→    output.append(r1);
   273→    if count == 2 {
   274→        return;
   275→    }
   276→    let (acc5, r2) = bounded_int_div_rem(acc6, NZ_Q);
   277→    output.append(r2);
   278→    if count == 3 {
   279→        return;
   280→    }
   281→    let (acc4, r3) = bounded_int_div_rem(acc5, NZ_Q);
   282→    output.append(r3);
   283→    if count == 4 {
   284→        return;
   285→    }
   286→    let (acc3, r4) = bounded_int_div_rem(acc4, NZ_Q);
   287→    output.append(r4);
   288→    if count == 5 {
   289→        return;
   290→    }
   291→    let (acc2, r5) = bounded_int_div_rem(acc3, NZ_Q);
   292→    output.append(r5);
   293→    if count == 6 {
   294→        return;
   295→    }
   296→    let (acc1, r6) = bounded_int_div_rem(acc2, NZ_Q);
   297→    output.append(r6);
   298→    if count == 7 {
   299→        return;
   300→    }
   301→    let (acc0, r7) = bounded_int_div_rem(acc1, NZ_Q);
   302→    output.append(r7);
   303→    if count == 8 {
   304→        return;
   305→    }
   306→    output.append(acc0);
   307→}
   308→
   309→/// Unpack a u128 into exactly 9 Zq values. No count checks.
   310→fn unpack_9_full(packed: u128, ref output: Array<Zq>) {
   311→    let acc8: Acc8 = downcast(packed).expect('bad pack');
   312→    let (acc7, r0) = bounded_int_div_rem(acc8, NZ_Q);
   313→    output.append(r0);
   314→    let (acc6, r1) = bounded_int_div_rem(acc7, NZ_Q);
   315→    output.append(r1);
   316→    let (acc5, r2) = bounded_int_div_rem(acc6, NZ_Q);
   317→    output.append(r2);
   318→    let (acc4, r3) = bounded_int_div_rem(acc5, NZ_Q);
   319→    output.append(r3);
   320→    let (acc3, r4) = bounded_int_div_rem(acc4, NZ_Q);
   321→    output.append(r4);
   322→    let (acc2, r5) = bounded_int_div_rem(acc3, NZ_Q);
   323→    output.append(r5);
   324→    let (acc1, r6) = bounded_int_div_rem(acc2, NZ_Q);
   325→    output.append(r6);
   326→    let (acc0, r7) = bounded_int_div_rem(acc1, NZ_Q);
   327→    output.append(r7);
   328→    output.append(acc0);
   329→}
   330→
   331→/// Unpack a u128 into exactly 8 Zq values (7 div_rems + final quotient).
   332→fn unpack_8(packed: u128, ref output: Array<Zq>) {
   333→    let acc7: Acc7 = downcast(packed).expect('bad pack');
   334→    let (acc6, r0) = bounded_int_div_rem(acc7, NZ_Q);
   335→    output.append(r0);
   336→    let (acc5, r1) = bounded_int_div_rem(acc6, NZ_Q);
   337→    output.append(r1);
   338→    let (acc4, r2) = bounded_int_div_rem(acc5, NZ_Q);
   339→    output.append(r2);
   340→    let (acc3, r3) = bounded_int_div_rem(acc4, NZ_Q);
   341→    output.append(r3);
   342→    let (acc2, r4) = bounded_int_div_rem(acc3, NZ_Q);
   343→    output.append(r4);
   344→    let (acc1, r5) = bounded_int_div_rem(acc2, NZ_Q);
   345→    output.append(r5);
   346→    let (acc0, r6) = bounded_int_div_rem(acc1, NZ_Q);
   347→    output.append(r6);
   348→    output.append(acc0);
   349→}
   350→
   351→/// Pack 512 Zq values into 29 felt252 slots.
   352→/// Each slot encodes up to 18 values: pack_9(lo) + pack_9(hi) * 2^128.
   353→pub fn pack_public_key(values: Span<Zq>) -> Array<felt252> {
   354→    assert!(values.len() == 512, "expected 512 values");
   355→    let mut result: Array<felt252> = array![];
   356→    let mut offset: usize = 0;
   357→    // 28 full slots: 9 lo + 9 hi = 18 values each (504 total)
   358→    while offset != 504 {
   359→        let lo_felt: felt252 = pack_9(values.slice(offset, 9)).into();
   360→        let hi_felt: felt252 = pack_9(values.slice(offset + 9, 9)).into();
   361→        result.append(lo_felt + hi_felt * TWO_POW_128);
   362→        offset += 18;
   363→    }
   364→    // Last slot: 8 remaining values in low half only
   365→    result.append(pack_9(values.slice(504, 8)).into());
   366→    result
   367→}
   368→
   369→/// Unpack 29 felt252 slots back to 512 Zq values.
   370→pub fn unpack_public_key(packed: Span<felt252>) -> Array<Zq> {
   371→    let mut output: Array<Zq> = array![];
   372→    let mut packed = packed;
   373→    // 28 full slots: 9 lo + 9 hi = 18 values each (504 total)
   374→    let mut i: usize = 0;
   375→    while i != 28 {
   376→        let val_u256: u256 = (*packed.pop_front().unwrap()).into();
   377→        unpack_9_full(val_u256.low, ref output);
   378→        unpack_9_full(val_u256.high, ref output);
   379→        i += 1;
   380→    }
   381→    // Last slot: 8 remaining values in low half
   382→    let val_u256: u256 = (*packed.pop_front().unwrap()).into();
   383→    unpack_8(val_u256.low, ref output);
   384→    output
   385→}
   386→
   387→// =============================================================================
   388→// PackedPolynomial512: storage-friendly struct for 512 Zq coefficients
   389→// =============================================================================
   390→
   391→/// A polynomial of 512 Zq coefficients packed into 29 felt252 fields.
   392→/// Suitable for Starknet storage (each field maps to a single storage slot).
   393→#[derive(Drop, Copy, Serde)]
   394→pub struct PackedPolynomial512 {
   395→    pub s0: felt252,
   396→    pub s1: felt252,
   397→    pub s2: felt252,
   398→    pub s3: felt252,
   399→    pub s4: felt252,
   400→    pub s5: felt252,
   401→    pub s6: felt252,
   402→    pub s7: felt252,
   403→    pub s8: felt252,
   404→    pub s9: felt252,
   405→    pub s10: felt252,
   406→    pub s11: felt252,
   407→    pub s12: felt252,
   408→    pub s13: felt252,
   409→    pub s14: felt252,
   410→    pub s15: felt252,
   411→    pub s16: felt252,
   412→    pub s17: felt252,
   413→    pub s18: felt252,
   414→    pub s19: felt252,
   415→    pub s20: felt252,
   416→    pub s21: felt252,
   417→    pub s22: felt252,
   418→    pub s23: felt252,
   419→    pub s24: felt252,
   420→    pub s25: felt252,
   421→    pub s26: felt252,
   422→    pub s27: felt252,
   423→    pub s28: felt252,
   424→}
   425→
   426→#[generate_trait]
   427→pub impl PackedPolynomial512Impl of PackedPolynomial512Trait {
   428→    /// Pack 512 Zq coefficients into a `PackedPolynomial512`.
   429→    fn from_coeffs(values: Span<Zq>) -> PackedPolynomial512 {
   430→        let packed = pack_public_key(values);
   431→        let s = packed.span();
   432→        PackedPolynomial512 {
   433→            s0: *s.at(0),
   434→            s1: *s.at(1),
   435→            s2: *s.at(2),
   436→            s3: *s.at(3),
   437→            s4: *s.at(4),
   438→            s5: *s.at(5),
   439→            s6: *s.at(6),
   440→            s7: *s.at(7),
   441→            s8: *s.at(8),
   442→            s9: *s.at(9),
   443→            s10: *s.at(10),
   444→            s11: *s.at(11),
   445→            s12: *s.at(12),
   446→            s13: *s.at(13),
   447→            s14: *s.at(14),
   448→            s15: *s.at(15),
   449→            s16: *s.at(16),
   450→            s17: *s.at(17),
   451→            s18: *s.at(18),
   452→            s19: *s.at(19),
   453→            s20: *s.at(20),
   454→            s21: *s.at(21),
   455→            s22: *s.at(22),
   456→            s23: *s.at(23),
   457→            s24: *s.at(24),
   458→            s25: *s.at(25),
   459→            s26: *s.at(26),
   460→            s27: *s.at(27),
   461→            s28: *s.at(28),
   462→        }
   463→    }
   464→
   465→    /// Unpack back to 512 Zq coefficients.
   466→    fn to_coeffs(self: @PackedPolynomial512) -> Array<Zq> {
   467→        unpack_public_key(self.to_span())
   468→    }
   469→
   470→    /// Return the 29 packed felt252 values as a span.
   471→    fn to_span(self: @PackedPolynomial512) -> Span<felt252> {
   472→        array![
   473→            *self.s0, *self.s1, *self.s2, *self.s3, *self.s4, *self.s5, *self.s6, *self.s7,
   474→            *self.s8, *self.s9, *self.s10, *self.s11, *self.s12, *self.s13, *self.s14, *self.s15,
   475→            *self.s16, *self.s17, *self.s18, *self.s19, *self.s20, *self.s21, *self.s22, *self.s23,
   476→            *self.s24, *self.s25, *self.s26, *self.s27, *self.s28,
