    11→# Starknet DeFi Skill
    12→
    13→Execute DeFi operations on Starknet using avnu aggregator and native protocols.
    14→
    15→## Prerequisites
    16→
    17→```bash
    18→npm install starknet@^8.9.1 @avnu/avnu-sdk@^4.0.1
    19→```
    20→
    21→## Token Swaps (avnu SDK v4)
    22→
    23→### Get Quote and Execute Swap
    24→
    25→```typescript
    26→import { getQuotes, executeSwap, type QuoteRequest } from "@avnu/avnu-sdk";
    27→import { Account, RpcProvider, ETransactionVersion } from "starknet";
    28→
    29→const provider = new RpcProvider({ nodeUrl: process.env.STARKNET_RPC_URL });
    30→
    31→// starknet.js v8: Account uses options object
    32→const account = new Account({
    33→  provider,
    34→  address,
    35→  signer: privateKey,
    36→  transactionVersion: ETransactionVersion.V3,
    37→});
    38→
    39→// Resolve token addresses via avnu SDK (or use MCP server's TokenService)
    40→import { fetchVerifiedTokenBySymbol } from '@avnu/avnu-sdk';
    41→
    42→const eth = await fetchVerifiedTokenBySymbol('ETH');
    43→const strk = await fetchVerifiedTokenBySymbol('STRK');
    44→
    45→// SDK v4: getQuotes takes QuoteRequest object directly
    46→const quoteParams: QuoteRequest = {
    47→  sellTokenAddress: eth.address,
    48→  buyTokenAddress: strk.address,
    49→  sellAmount: BigInt(10 ** 17), // 0.1 ETH
    50→  takerAddress: account.address,
    51→};
    52→
    53→const quotes = await getQuotes(quoteParams);
    54→const bestQuote = quotes[0];
    55→
    56→// SDK v4: executeSwap takes single object param
    57→const result = await executeSwap({
    58→  provider: account,
    59→  quote: bestQuote,
    60→  slippage: 0.01, // 1%
    61→  executeApprove: true,
    62→});
    63→console.log("Tx:", result.transactionHash);
    64→```
    65→
    66→### Quote Response Fields (SDK v4)
    67→
    68→```typescript
    69→interface Quote {
    70→  quoteId: string;
    71→  sellTokenAddress: string;
    72→  buyTokenAddress: string;
    73→  sellAmount: bigint;
    74→  buyAmount: bigint;
    75→  sellAmountInUsd: number;
    76→  buyAmountInUsd: number;
    77→  priceImpact: number;        // In basis points (15 = 0.15%)
    78→  gasFeesInUsd: number;
    79→  routes: Array<{
    80→    name: string;             // e.g., "Ekubo", "JediSwap"
    81→    percent: number;          // e.g., 0.8 = 80%
    82→  }>;
    83→  fee: {
    84→    avnuFees: bigint;
    85→    integratorFees: bigint;
    86→  };
    87→}
    88→```
