   284→## Error Handling
   285→
   286→```typescript
   287→async function safeSwap(account, quote, slippage = 0.01) {
   288→  try {
   289→    return await executeSwap({
   290→      provider: account,
   291→      quote,
   292→      slippage,
   293→      executeApprove: true,
   294→    });
   295→  } catch (error) {
   296→    if (error.message?.includes("INSUFFICIENT_BALANCE")) {
   297→      throw new Error("Not enough tokens for swap");
   298→    }
   299→    if (error.message?.includes("SLIPPAGE") || error.message?.includes("Insufficient tokens received")) {
   300→      // Retry with higher slippage
   301→      return await executeSwap({
   302→        provider: account,
   303→        quote,
   304→        slippage: slippage * 2,
   305→        executeApprove: true,
   306→      });
   307→    }
   308→    if (error.message?.includes("QUOTE_EXPIRED")) {
   309→      throw new Error("Quote expired. Please retry the operation.");
   310→    }
   311→    if (error.message?.includes("INSUFFICIENT_LIQUIDITY")) {
   312→      throw new Error("Insufficient liquidity. Try a smaller amount.");
   313→    }
   314→    throw error;
   315→  }
   316→}
   317→```
