    10→import 'dotenv/config';
    11→import { RpcProvider, Contract, uint256 } from 'starknet';
    12→import { fetchTokenByAddress, fetchVerifiedTokenBySymbol } from '@avnu/avnu-sdk';
    13→
    14→const ERC20_ABI = [{
    15→  name: 'balanceOf',
    16→  type: 'function',
    17→  inputs: [{ name: 'account', type: 'felt' }],
    18→  outputs: [{ name: 'balance', type: 'Uint256' }],
    19→  stateMutability: 'view',
    20→}];
    21→
    22→type TokenInfo = {
    23→  address: string;
    24→  symbol: string;
    25→  decimals: number;
    26→};
    27→
    28→async function resolveToken(tokenSymbolOrAddress?: string): Promise<TokenInfo> {
    29→  if (!tokenSymbolOrAddress || tokenSymbolOrAddress.toUpperCase() === 'ETH') {
    30→    const token = await fetchVerifiedTokenBySymbol('ETH');
    31→    return { address: token.address, symbol: token.symbol, decimals: token.decimals };
    32→  }
    33→
    34→  if (tokenSymbolOrAddress.startsWith('0x')) {
    35→    const token = await fetchTokenByAddress(tokenSymbolOrAddress);
    36→    return { address: token.address, symbol: token.symbol, decimals: token.decimals };
    37→  }
    38→
    39→  const token = await fetchVerifiedTokenBySymbol(tokenSymbolOrAddress);
    40→  return { address: token.address, symbol: token.symbol, decimals: token.decimals };
    41→}
