     1→#!/usr/bin/env tsx
     2→/**
     3→ * Check Multiple Token Balances (Batch)
     4→ *
     5→ * Tests the batch balance fetching logic from starknet-mcp-server.
     6→ * Uses BalanceChecker contract with fallback to batch RPC.
     7→ *
     8→ * Usage: tsx check-balances.ts
     9→ * Requires .env with STARKNET_RPC_URL and STARKNET_ACCOUNT_ADDRESS
    10→ */
    11→
    12→import 'dotenv/config';
    13→import { RpcProvider, Contract, uint256 } from 'starknet';
    14→import { fetchVerifiedTokenBySymbol } from '@avnu/avnu-sdk';
    15→
    16→const DEFAULT_TOKENS = ['ETH', 'STRK', 'USDC', 'USDT'];
    17→const BALANCE_CHECKER_ADDRESS = '0x031ce64a666fbf9a2b1b2ca51c2af60d9a76d3b85e5fbfb9d5a8dbd3fedc9716';
    18→
    19→const BALANCE_CHECKER_ABI = [
    20→  {
    21→    type: 'struct',
    22→    name: 'core::integer::u256',
    23→    members: [
    24→      { name: 'low', type: 'core::integer::u128' },
    25→      { name: 'high', type: 'core::integer::u128' },
    26→    ],
    27→  },
    28→  {
    29→    type: 'struct',
    30→    name: 'governance::balance_checker::NonZeroBalance',
    31→    members: [
    32→      { name: 'token', type: 'core::starknet::contract_address::ContractAddress' },
    33→      { name: 'balance', type: 'core::integer::u256' },
    34→    ],
    35→  },
    36→  {
    37→    type: 'function',
    38→    name: 'get_balances',
    39→    inputs: [
    40→      { name: 'address', type: 'core::starknet::contract_address::ContractAddress' },
    41→      { name: 'tokens', type: 'core::array::Span::<core::starknet::contract_address::ContractAddress>' },
    42→    ],
    43→    outputs: [
    44→      { type: 'core::array::Span::<governance::balance_checker::NonZeroBalance>' },
    45→    ],
    46→    state_mutability: 'view',
    47→  },
    48→];
    49→
    50→const ERC20_ABI = [{
    51→  name: 'balanceOf',
    52→  type: 'function',
    53→  inputs: [{ name: 'account', type: 'felt' }],
    54→  outputs: [{ name: 'balance', type: 'Uint256' }],
    55→  stateMutability: 'view',
    56→}];
    57→
    58→type TokenInfo = {
    59→  symbol: string;
    60→  address: string;
    61→  decimals: number;
    62→};
    63→
    64→type TokenBalanceResult = {
    65→  token: string;
    66→  tokenAddress: string;
    67→  balance: bigint;
    68→  decimals: number;
    69→};
    70→
    71→function normalizeAddress(addr: string): string {
    72→  return '0x' + BigInt(addr).toString(16).padStart(64, '0');
    73→}
    74→
    75→function formatAmount(amount: bigint, decimals: number): string {
    76→  if (decimals === 0) {
    77→    return amount.toString();
    78→  }
    79→  const amountStr = amount.toString().padStart(decimals + 1, '0');
    80→  const whole = amountStr.slice(0, -decimals) || '0';
    81→  const fraction = amountStr.slice(-decimals).slice(0, 6);
    82→  return `${whole}.${fraction}`;
    83→}
    84→
    85→async function fetchTokenInfo(symbols: string[]): Promise<TokenInfo[]> {
    86→  return Promise.all(
    87→    symbols.map(async (symbol) => {
    88→      const token = await fetchVerifiedTokenBySymbol(symbol);
    89→      return {
    90→        symbol,
    91→        address: token.address,
    92→        decimals: token.decimals,
    93→      };
    94→    })
    95→  );
    96→}
    97→
    98→async function fetchViaBalanceChecker(
    99→  provider: RpcProvider,
   100→  walletAddress: string,
   101→  tokenInfos: TokenInfo[]
   102→): Promise<TokenBalanceResult[]> {
   103→  const balanceChecker = new Contract({
   104→    abi: BALANCE_CHECKER_ABI,
   105→    address: BALANCE_CHECKER_ADDRESS,
   106→    providerOrAccount: provider,
   107→  });
   108→  const tokenAddresses = tokenInfos.map((t) => t.address);
   109→  const result = await balanceChecker.get_balances(walletAddress, tokenAddresses);
   110→
   111→  const balanceMap = new Map<string, bigint>();
   112→  for (const item of result) {
   113→    const addr = normalizeAddress('0x' + BigInt(item.token).toString(16));
   114→    const balance = typeof item.balance === 'bigint'
   115→      ? item.balance
   116→      : uint256.uint256ToBN(item.balance);
   117→    balanceMap.set(addr, balance);
   118→  }
   119→
   120→  return tokenInfos.map((info) => ({
   121→    token: info.symbol,
   122→    tokenAddress: info.address,
   123→    balance: balanceMap.get(normalizeAddress(info.address)) ?? BigInt(0),
   124→    decimals: info.decimals,
   125→  }));
   126→}
   127→
   128→async function fetchViaBatchRpc(
   129→  provider: RpcProvider,
   130→  walletAddress: string,
   131→  tokenInfos: TokenInfo[]
   132→): Promise<TokenBalanceResult[]> {
   133→  const balanceResults = await Promise.all(
   134→    tokenInfos.map(async (info) => {
   135→      const contract = new Contract({
   136→        abi: ERC20_ABI,
   137→        address: info.address,
   138→        providerOrAccount: provider,
   139→      });
   140→      const balanceResult = await contract.balanceOf(walletAddress);
   141→      const rawBalance = balanceResult?.balance ?? balanceResult;
   142→      return typeof rawBalance === 'bigint' ? rawBalance : uint256.uint256ToBN(rawBalance);
   143→    })
   144→  );
   145→
   146→  return tokenInfos.map((info, i) => ({
   147→    token: info.symbol,
   148→    tokenAddress: info.address,
   149→    balance: balanceResults[i],
   150→    decimals: info.decimals,
   151→  }));
   152→}
   153→
   154→async function main(): Promise<void> {
   155→  const rpcUrl = process.env.STARKNET_RPC_URL;
   156→  const address = process.env.STARKNET_ACCOUNT_ADDRESS;
   157→
   158→  if (!rpcUrl || !address) {
   159→    console.error('Missing STARKNET_RPC_URL or STARKNET_ACCOUNT_ADDRESS');
   160→    process.exit(1);
   161→  }
   162→
   163→  console.log('Fetching token info from avnu...');
   164→  const tokenInfos = await fetchTokenInfo(DEFAULT_TOKENS);
   165→
   166→  const provider = new RpcProvider({ nodeUrl: rpcUrl, batch: 0 });
   167→  const tokens = tokenInfos.map((t) => t.symbol);
   168→
   169→  console.log(`Checking balances for ${address}\n`);
   170→  console.log(`Tokens: ${tokens.join(', ')}\n`);
   171→
   172→  let balances: TokenBalanceResult[];
   173→  let method: string;
   174→
   175→  try {
   176→    console.log('Trying BalanceChecker contract...');
   177→    balances = await fetchViaBalanceChecker(provider, address, tokenInfos);
   178→    method = 'balance_checker';
   179→    console.log('BalanceChecker succeeded\n');
   180→  } catch (err) {
   181→    console.log(`BalanceChecker failed: ${err instanceof Error ? err.message : err}`);
   182→    console.log('Falling back to batch RPC...');
   183→    balances = await fetchViaBatchRpc(provider, address, tokenInfos);
   184→    method = 'batch_rpc';
   185→    console.log('Batch RPC succeeded\n');
   186→  }
   187→
   188→  console.log('━'.repeat(60));
   189→  console.log('Token'.padEnd(8) + 'Balance'.padEnd(20) + 'Raw');
   190→  console.log('━'.repeat(60));
   191→
   192→  for (const b of balances) {
   193→    const formatted = formatAmount(b.balance, b.decimals);
   194→    console.log(
   195→      b.token.padEnd(8) +
   196→      formatted.padEnd(20) +
   197→      b.balance.toString()
   198→    );
   199→  }
   200→
   201→  console.log('━'.repeat(60));
   202→  console.log(`\nMethod: ${method}`);
   203→  console.log(`Tokens queried: ${tokens.length}`);
   204→}
   205→
   206→main().catch((error) => {
   207→  console.error('Error:', error);
   208→  process.exit(1);
   209→});
